class Solution {
public:
    string longestCommonPrefix(vector<string>& strs) {
        int n = strs.size();
        if (n == 0)
            return "";

        int str_len = strs[0].size();

        int length = 0;

        for(int x = 0; x < str_len; x++){

            char pre = strs[0][x];
            for(int i = 0; i < n; i++){
                if(strs[i].size() < x || strs[i][x] != pre)
                    return strs[0].substr(0, length);

            }
            length++;
        }
        return strs[0].substr(0, length);

    }
};
